        assertEquals(1, vm.state.value.cart.size)
    }

    @Test
    fun `invoice denied for empty cart`() {
        val vm = createVm()
        vm.generateInvoice(Role.Admin, "admin")

        // Empty cart = no-op
        assertTrue(vm.state.value.invoices.isEmpty())
    }
}

