            // ΓöÇΓöÇ Cart & Invoice ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            item(key = "finance") {
                SectionCard(
                    title = "Cart & Invoice",
                    subtitle = financeState.note,
                    accent = Amber,
                    modifier = Modifier.padding(horizontal = 16.dp, vertical = 6.dp),
                ) {
                    Text(
                        "Cart Actions",
                        style = MaterialTheme.typography.labelMedium,
                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                    )
                    Spacer(Modifier.height(6.dp))
                    FlowRow(
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalArrangement = Arrangement.spacedBy(8.dp),
                    ) {
                        ActionChip("Add Item", Green, canManage) {
                            orderFinanceViewModel.addDemoItem(actorRole, actorId)
                            onActivity()
                        }
                        ActionChip("Merge", Blue, canManage) {
                            orderFinanceViewModel.mergeFirstTwoItems(actorRole, actorId)
                            onActivity()
                        }
                        ActionChip("Split", Amber, canManage) {
                            orderFinanceViewModel.splitFirstItem(actorRole, actorId)
                            onActivity()
                        }
                    }

                    Spacer(Modifier.height(14.dp))
                    Text(
                        "Billing",
                        style = MaterialTheme.typography.labelMedium,
                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                    )
                    Spacer(Modifier.height(6.dp))
                    FlowRow(
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalArrangement = Arrangement.spacedBy(8.dp),
                    ) {
                        ActionChip("Generate Invoice", Purple, canManage) {
                            orderFinanceViewModel.generateInvoice(role = actorRole, actorId = actorId)
                            onActivity()
                        }
                        ActionChip("Refund Latest", Coral, canManage) {
                            orderFinanceViewModel.refundLatest(role = actorRole, actorId = actorId)
                            onActivity()
                        }
                    }
                }
            }

            // ΓöÇΓöÇ Resource catalog header ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            item(key = "catalog-header") {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 20.dp)
                        .padding(top = 16.dp, bottom = 8.dp),
                    verticalAlignment = Alignment.CenterVertically,
                ) {
                    Text(
                        text = "Resource Catalog",
                        style = MaterialTheme.typography.titleLarge,
                        color = MaterialTheme.colorScheme.onBackground,
                    )
                    Spacer(Modifier.weight(1f))
                    Text(
                        text = "${state.resources.size} items",
                        style = MaterialTheme.typography.labelMedium,
                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                    )
                }
            }

            // ΓöÇΓöÇ Resource cards (RecyclerView + DiffUtil on Android) ΓöÇ
            item(key = "resource-list") {
                PlatformResourceList(
                    resources = state.resources,
                    roleLabel = roleLabel,
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(if (state.resources.isEmpty()) 100.dp else 600.dp),
