            financeVm.generateInvoice(role, actorId, delegateForUserId)
            authVm.touchSession()
        }
        view.findViewById<MaterialButton>(R.id.invoiceBtn).setOnClickListener {
            val invoiceId = financeVm.state.value.invoices.lastOrNull()?.id
